// The user manual structure: task-oriented sections, each with a screenshot, a
// localized title + body (what the controls do and produce), and the inventory ids
// it documents. The Help page renders this; coverage.test.ts asserts that every
// INVENTORY id appears in exactly one section's `covers` (the goal's STOP condition).
//
// titleKey → help.tasks.<id>.title, bodyKey → help.tasks.<id>.body (i18n catalog).
// shot → static/manual/<shot>.png (dark-mode screenshot generated by manual-shots.e2e.ts).

import { isExperimentalId } from './inventory';

export interface ManualSection {
	id: string;
	titleKey: string;
	bodyKey: string;
	shot: string;
	covers: string[];
	/** Wholly-experimental section (CBCT/IOS 3D, photos, FMX): only shown in-app when
	 *  the viewer has Labs access; always omitted from the manual PDF. */
	experimental?: boolean;
}

const section = (
	id: string,
	shot: string,
	covers: string[],
	experimental = false
): ManualSection => ({
	id,
	titleKey: `help.tasks.${id}.title`,
	bodyKey: `help.tasks.${id}.body`,
	shot,
	covers,
	experimental
});

