/** The manual sections to actually render, given viewer access.
 *  - In-app, a viewer with Labs (`labs`) sees everything; without it, experimental
 *    sections are dropped and experimental controls are filtered out of core sections.
 *  - For the PDF (`pdf: true`) experimental content is ALWAYS omitted, regardless of
 *    Labs — the printed manual documents the baseline product only.
 *  Section order is preserved (experimental sections live at the end of MANUAL), and a
 *  section left empty after filtering is dropped. */
export function visibleSections({ labs, pdf }: { labs: boolean; pdf: boolean }): ManualSection[] {
	const showExperimental = labs && !pdf;
	return MANUAL.filter((s) => showExperimental || !s.experimental)
		.map((s) =>
			showExperimental ? s : { ...s, covers: s.covers.filter((id) => !isExperimentalId(id)) }
		)
		.filter((s) => s.covers.length > 0);
}
